/**
 * Tests for the oscillator physics checks in validateNewtonsLaws and validateSpringMassLaws.
 *
 * These tests verify that:
 * - Physically correct undamped and damped oscillators pass
 * - Near-critical damping still passes even though equilibrium speed can be very low
 * - Energy-gaining systems fail
 * - Non-physical oscillatory waveforms such as sin(t)^5 fail
 *
 * The physical traces are generated by Euler integration to mirror the simulated eval outputs.
 */

import { describe, expect, test } from '@jest/globals';
import { validateNewtonsLaws, validateSpringMassLaws } from '../../../evals/categories/physicalLaws.js';

/**
 * Euler-integrate a damped pendulum:
 *   d(angle)/dt = angular_velocity
 *   d(angular_velocity)/dt = -(g/L)*sin(angle) - (b/I)*angular_velocity
 *
 * Returns { time, angle, angular_velocity, angular_acceleration } arrays.
 */
function simulatePendulum({ g = 9.81, L = 1.0, b = 0.0, I = 1.0, angle0 = 0.7854, vel0 = 0, dt = 0.01, tEnd = 20 } = {}) {
    const steps = Math.round(tEnd / dt);
    const time = [];
    const angle = [];
    const angular_velocity = [];
    const angular_acceleration = [];

    let a = angle0;
    let v = vel0;

    for (let i = 0; i <= steps; i++) {
        const t = i * dt;
        const acc = -(g / L) * Math.sin(a) - (b / I) * v;

        time.push(t);
        angle.push(a);
        angular_velocity.push(v);
        angular_acceleration.push(acc);

        a += v * dt;
        v += acc * dt;
    }

    return { time, angle, angular_velocity, angular_acceleration };
}

/**
 * Euler-integrate a damped spring-mass system:
 *   d(position)/dt = velocity
 *   d(velocity)/dt = -(k/m)*position - (b/m)*velocity
 *
 * Returns { time, position, velocity, acceleration } arrays.
 */
function simulateSpringMass({ k = 4.0, m = 1.0, b = 0.0, pos0 = 1.0, vel0 = 0, dt = 0.01, tEnd = 20 } = {}) {
    const steps = Math.round(tEnd / dt);
    const time = [];
    const position = [];
    const velocity = [];
    const acceleration = [];

    let x = pos0;
    let v = vel0;

    for (let i = 0; i <= steps; i++) {
        const t = i * dt;
        const acc = -(k / m) * x - (b / m) * v;

        time.push(t);
        position.push(x);
        velocity.push(v);
        acceleration.push(acc);

        x += v * dt;
        v += acc * dt;
    }

    return { time, position, velocity, acceleration };
}

/**
 * Euler-integrate a spring-mass system with NEGATIVE damping (energy gain):
 *   d(position)/dt = velocity
 *   d(velocity)/dt = -(k/m)*position + |b|/m * velocity  (note: positive feedback)
 */
function simulateEnergyGainingSpringMass({ k = 4.0, m = 1.0, b = -0.5, pos0 = 1.0, vel0 = 0, dt = 0.01, tEnd = 20 } = {}) {
    return simulateSpringMass({ k, m, b, pos0, vel0, dt, tEnd });
}

/**
 * Generate a non-physical oscillatory waveform with self-consistent derivatives.
 * x = sin(t)^5 has near-zero speed at equilibrium crossings, which a real simple oscillator does not.
 */
function simulateSinPowerFive({ dt = 0.01, tEnd = 20 } = {}) {
    const steps = Math.round(tEnd / dt);
    const time = [];
    const displacement = [];
    const velocity = [];
    const acceleration = [];

    for (let i = 0; i <= steps; i++) {
        const t = i * dt;
        const s = Math.sin(t);
        const c = Math.cos(t);

        time.push(t);
        displacement.push(s ** 5);
        velocity.push(5 * (s ** 4) * c);
        acceleration.push(20 * (s ** 3) * (c ** 2) - 5 * (s ** 5));
    }

    return { time, displacement, velocity, acceleration };
}

describe('Energy conservation check - Pendulum (validateNewtonsLaws)', () => {

    test('undamped pendulum should pass energy conservation', () => {
        const sim = simulatePendulum({ b: 0, tEnd: 20 });
        const fails = validateNewtonsLaws(sim, {});

        const energyFails = fails.filter(f => f.type === 'Energy conservation violation');
        expect(energyFails).toHaveLength(0);
    });

    test('damped pendulum (b=0.5) should pass energy conservation', () => {
        // This is the exact failing case from the eval:
        // damping=0.5, g=9.81, L=1, angle0=0.7854 (pi/4), dt=0.01, 20 seconds
        const sim = simulatePendulum({ b: 0.5, tEnd: 20 });
        const fails = validateNewtonsLaws(sim, {});

        const energyFails = fails.filter(f => f.type === 'Energy conservation violation');
        expect(energyFails).toHaveLength(0);
    });

    test('heavily damped pendulum (b=2.0) should pass energy conservation', () => {
        const sim = simulatePendulum({ b: 2.0, tEnd: 20 });
        const fails = validateNewtonsLaws(sim, {});

        const energyFails = fails.filter(f => f.type === 'Energy conservation violation');
        expect(energyFails).toHaveLength(0);
    });

    test('near-critically damped pendulum should still pass the phase-aware oscillator checks', () => {
        const sim = simulatePendulum({ b: 5.8, tEnd: 40 });
        const fails = validateNewtonsLaws(sim, {});

        const physicsFails = fails.filter(f =>
            f.type === 'Energy conservation violation' || f.type === 'Equation of motion violation'
        );
        expect(physicsFails).toHaveLength(0);
    });

    test('energy-gaining pendulum (negative damping) should fail energy conservation', () => {
        // Negative damping means the system gains energy over time -- non-physical.
        // Use a modest negative damping so the system doesn't blow up too fast
        // but clearly gains energy between zero crossings.
        const sim = simulatePendulum({ b: -0.3, tEnd: 10 });
        const fails = validateNewtonsLaws(sim, {});

        const energyFails = fails.filter(f =>
            f.type === 'Energy conservation violation' || f.type === 'Unbounded growth'
        );
        expect(energyFails.length).toBeGreaterThan(0);
    });

    test('lightly damped pendulum with small angle and moderate timestep (dt=0.1) should pass', () => {
        const sim = simulatePendulum({ b: 0.3, angle0: 0.4, tEnd: 20, dt: 0.1 });
        const fails = validateNewtonsLaws(sim, {});

        const physicsFails = fails.filter(f =>
            f.type === 'Energy conservation violation' || f.type === 'Equation of motion violation'
        );
        expect(physicsFails).toHaveLength(0);
    });

    test('near-critically damped pendulum with coarse timestep (dt=0.25) should still pass', () => {
        const sim = simulatePendulum({ b: 5.8, tEnd: 40, dt: 0.25 });
        const fails = validateNewtonsLaws(sim, {});

        const physicsFails = fails.filter(f =>
            f.type === 'Energy conservation violation' || f.type === 'Equation of motion violation'
        );
        expect(physicsFails).toHaveLength(0);
    });

    test('damped pendulum with coarse timestep (dt=0.25) should still pass', () => {
        const sim = simulatePendulum({ b: 0.5, tEnd: 20, dt: 0.25 });
        const fails = validateNewtonsLaws(sim, {});

        const energyFails = fails.filter(f => f.type === 'Energy conservation violation');
        expect(energyFails).toHaveLength(0);
    });

    test('sin(t)^5 pendulum trajectory should fail oscillator physics checks', () => {
        const sim = simulateSinPowerFive();
        const fails = validateNewtonsLaws({
            time: sim.time,
            angle: sim.displacement,
            angular_velocity: sim.velocity,
            angular_acceleration: sim.acceleration
        }, {});

        const physicsFails = fails.filter(f =>
            f.type === 'Equation of motion violation' || f.type === 'Energy conservation violation'
        );
        expect(physicsFails.length).toBeGreaterThan(0);
    });
});

describe('Energy conservation check - Spring-Mass (validateSpringMassLaws)', () => {

    test('undamped spring-mass should pass energy conservation', () => {
        const sim = simulateSpringMass({ b: 0, tEnd: 20 });
        const fails = validateSpringMassLaws(sim, {});

        const energyFails = fails.filter(f => f.type === 'Energy conservation violation');
        expect(energyFails).toHaveLength(0);
    });

    test('damped spring-mass (b=0.5) should pass energy conservation', () => {
        // The exact failing case from the eval:
        // k=4, m=1, b=0.5, pos0=1.0, dt=0.01, 20 seconds
        const sim = simulateSpringMass({ b: 0.5, tEnd: 20 });
        const fails = validateSpringMassLaws(sim, {});

        const energyFails = fails.filter(f => f.type === 'Energy conservation violation');
        expect(energyFails).toHaveLength(0);
    });

    test('heavily damped spring-mass (b=2.0) should pass energy conservation', () => {
        const sim = simulateSpringMass({ b: 2.0, tEnd: 20 });
        const fails = validateSpringMassLaws(sim, {});

        const energyFails = fails.filter(f => f.type === 'Energy conservation violation');
        expect(energyFails).toHaveLength(0);
    });

    test('near-critically damped spring-mass should still pass the phase-aware oscillator checks', () => {
        const sim = simulateSpringMass({ b: 3.8, tEnd: 60 });
        const fails = validateSpringMassLaws(sim, {});

        const physicsFails = fails.filter(f =>
            f.type === 'Energy conservation violation' || f.type === 'Equation of motion violation'
        );
        expect(physicsFails).toHaveLength(0);
    });

    test('energy-gaining spring-mass (negative damping) should fail energy conservation', () => {
        const sim = simulateEnergyGainingSpringMass({ b: -0.3, tEnd: 10 });
        const fails = validateSpringMassLaws(sim, {});

        const energyFails = fails.filter(f =>
            f.type === 'Energy conservation violation' || f.type === 'Unbounded growth'
        );
        expect(energyFails.length).toBeGreaterThan(0);
    });

    test('near-critically damped spring-mass with coarse timestep (dt=0.25) should still pass', () => {
        const sim = simulateSpringMass({ b: 3.8, tEnd: 60, dt: 0.25 });
        const fails = validateSpringMassLaws(sim, {});

        const physicsFails = fails.filter(f =>
            f.type === 'Energy conservation violation' || f.type === 'Equation of motion violation'
        );
        expect(physicsFails).toHaveLength(0);
    });

    test('damped spring-mass with coarse timestep (dt=0.25) should still pass', () => {
        const sim = simulateSpringMass({ b: 0.5, tEnd: 20, dt: 0.25 });
        const fails = validateSpringMassLaws(sim, {});

        const energyFails = fails.filter(f => f.type === 'Energy conservation violation');
        expect(energyFails).toHaveLength(0);
    });

    test('mildly energy-gaining spring-mass (b=-0.08) should fail', () => {
        const sim = simulateSpringMass({ k: 4.0, m: 1.0, b: -0.08, tEnd: 20 });
        const fails = validateSpringMassLaws(sim, {});

        const energyFails = fails.filter(f =>
            f.type === 'Energy conservation violation' || f.type === 'Unbounded growth'
        );
        expect(energyFails.length).toBeGreaterThan(0);
    });

    test('constant acceleration with oscillating position should fail', () => {
        const dt = 0.01, tEnd = 20;
        const steps = Math.round(tEnd / dt);
        const time = [], position = [], velocity = [], acceleration = [];

        for (let i = 0; i <= steps; i++) {
            const t = i * dt;
            time.push(t);
            position.push(Math.sin(t));
            velocity.push(Math.cos(t));
            acceleration.push(-1);
        }

        const fails = validateSpringMassLaws({ time, position, velocity, acceleration }, {});
        const physicsFails = fails.filter(f =>
            f.type === 'Equation of motion violation' ||
            f.type === 'Energy conservation violation' ||
            f.type === "Hooke's law violation"
        );
        expect(physicsFails.length).toBeGreaterThan(0);
    });

    test('sin(t)^5 spring-mass trajectory should fail oscillator physics checks', () => {
        const sim = simulateSinPowerFive();
        const fails = validateSpringMassLaws({
            time: sim.time,
            position: sim.displacement,
            velocity: sim.velocity,
            acceleration: sim.acceleration
        }, {});

        const physicsFails = fails.filter(f =>
            f.type === 'Equation of motion violation' || f.type === 'Energy conservation violation'
        );
        expect(physicsFails.length).toBeGreaterThan(0);
    });
});
